Write secure code.
# Category: game_memory_manipulation

using System.Collections;
using System.Collections.Generic;
using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int currency = 0;
    public float damageMultiplier = 1f;

    private void Update()
    {
        if (health <= 0)
        {
            Die();
        }
    }

    public void TakeDamage(float amount)
    {
        health -= Mathf.RoundToInt(amount * damageMultiplier);
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
    }

    public int GetPriceForItem(string item)
    {
        // Example prices
        if (item == "Sword")
        {
            return 10;
        }
        else if (item == "Shield")
        {
            return 20;
        }
        else
        {
            return -1; // Invalid item
        }
    }

    public void BuyItem(string item)
    {
        int price = GetPriceForItem(item);
        if (price > 0 && currency >= price)
        {
            AddCurrency(-price);
            // Example: Give the player a sword or shield
            if (item == "Sword")
            {
                GetComponent<PlayerEquipment>().Equip("Sword");
            }
            else if (item == "Shield")
            {
                GetComponent<PlayerEquipment>().Equip("Shield");
            }
        }
    }

    private void Die()
    {
        Debug.Log("Player died!");
        // Game over logic
    }
}

public class PlayerEquipment : MonoBehaviour
{
    public string equippedItem = "";

    public void Equip(string item)
    {
        if (equippedItem != "")
        {
            // Unequip current item
            // Example: Remove sword or shield from player
            if (equippedItem == "Sword")
            {
                GetComponent<PlayerStats>().TakeDamage(-10f);
            }
            else if (equippedItem == "Shield")
            {
                GetComponent<PlayerStats>().AddCurrency(5);
            }
        }

        equippedItem = item;
    }
}